SELECT Item.[Product Family], Item.[Product Sex], [Purch_ Price Model Item].[Model Item No_] AS Article, [Variable Code].[Variable Code], Min([Purch_ Price Model Item].[Variable Code 02]) AS FromSize, Max([Purch_ Price Model Item].[Variable Code 02]) AS ToSize, Val([Purch_ Price Model Item].[Direct Unit Cost]) AS PurchasePrice, Item.[Trademark Code], Item.Description, [Purch_ Price Model Item].[Variable Group 01], [Purch_ Price Model Item].[Variable Code 01], [Variable Code].Description, Item.[Line Code], Str(Min(Val([Purch_ Price Model Item].[variable code 02]))) & "-" & Str(Max(Val([Purch_ Price Model Item].[variable code 02]))) AS SizeRange, Item.[Season Code], Item.[Sales_Purchase Status Code]
FROM (Item INNER JOIN [Variable Code] ON Item.[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group]) INNER JOIN [Purch_ Price Model Item] ON (Item.No_ = [Purch_ Price Model Item].[Model Item No_]) AND ([Variable Code].[Variable Code] = [Purch_ Price Model Item].[Variable Code 01])
GROUP BY Item.[Product Family], Item.[Product Sex], [Purch_ Price Model Item].[Model Item No_], [Variable Code].[Variable Code], Val([Purch_ Price Model Item].[Direct Unit Cost]), Item.[Trademark Code], Item.Description, [Purch_ Price Model Item].[Variable Group 01], [Purch_ Price Model Item].[Variable Code 01], [Variable Code].Description, Item.[Line Code], Item.[Season Code], Item.[Sales_Purchase Status Code]
HAVING (((Item.[Trademark Code])=[marchio]) AND ((Item.[Season Code])=[stagione]));

